      tsh = "_tsh_function";
      tsk = "_tsk_function";
      tss = "_tss_function";
      tsw = "_tsw_function";
      two = "_two_function";
      zdo = "_zdo_function";
      zmo = "_zmo_function";
      zpo = "_zpo_function";
    };
    plugins = [
      {
        name = "autopair";
        src = pkgs.fishPlugins.autopair-fish.src;
      }
